import { create } from 'zustand';
import { Course, SupportedLanguage } from '@/types';

interface CourseState {
  currentCourse: Course | null;
  isGenerating: boolean;
  error: string | null;
  language: SupportedLanguage;
  query: string;
  setQuery: (query: string) => void;
  setLanguage: (language: SupportedLanguage) => void;
  setGenerating: (generating: boolean) => void;
  setCourse: (course: Course | null) => void;
  setError: (error: string | null) => void;
  generateCourse: (query: string, level: string) => Promise<void>;
}

export const useCourseStore = create<CourseState>((set, get) => ({
  currentCourse: null,
  isGenerating: false,
  error: null,
  language: 'hi',
  query: '',
  setQuery: (query) => set({ query }),
  setLanguage: (language) => set({ language }),
  setGenerating: (generating) => set({ isGenerating: generating }),
  setCourse: (course) => set({ currentCourse: course }),
  setError: (error) => set({ error }),
  generateCourse: async (query: string, level: string) => {
    set({ isGenerating: true, error: null });
    try {
      const response = await fetch('/api/course/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ query, level, language: get().language }),
      });
      if (!response.ok) throw new Error('Failed to generate course');
      const course = await response.json();
      set({ currentCourse: course, isGenerating: false, query: '' });
    } catch (error) {
      set({ error: error instanceof Error ? error.message : 'Something went wrong', isGenerating: false });
    }
  },
}));
