'use client';

import { useState } from 'react';

interface TextToSpeechPlayerProps {
  text: string;
  language: string;
}

export function TextToSpeechPlayer({ text, language }: TextToSpeechPlayerProps) {
  const [isPlaying, setIsPlaying] = useState(false);

  const playAudio = async () => {
    setIsPlaying(true);

    try {
      const response = await fetch('/api/voice/tts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text, language }),
      });

      const data = await response.json();

      if (data.audio) {
        // Sarvam API returned base64 audio
        const audioSrc = 'data:audio/wav;base64,' + data.audio;
        const audio = new Audio(audioSrc);
        audio.onended = () => setIsPlaying(false);
        audio.play();
      } else {
        // Fallback to browser TTS
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = language === 'hi' ? 'hi-IN' : 'en-IN';
        utterance.onend = () => setIsPlaying(false);
        speechSynthesis.speak(utterance);
      }
    } catch {
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = language === 'hi' ? 'hi-IN' : 'en-IN';
      utterance.onend = () => setIsPlaying(false);
      speechSynthesis.speak(utterance);
    }
  };

  return (
    <button
      onClick={playAudio}
      disabled={isPlaying}
      className="inline-flex items-center gap-1.5 text-sm text-orange-600 hover:text-orange-700 disabled:text-gray-400 transition-colors"
    >
      <svg className={'w-4 h-4' + (isPlaying ? ' animate-pulse' : '')} fill="currentColor" viewBox="0 0 24 24">
        <path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02z" />
      </svg>
      {isPlaying ? 'Playing...' : 'Listen'}
    </button>
  );
}
